`timescale 1ns / 1ps

module mux_4to1 (
  input  wire [3:0] iDataIn,
  input  wire [1:0] iSel,
  output reg        oDataOut
);

  always @(*) begin
    oDataOut = 1'b0;
    case (iSel)
      2'd0: oDataOut = iDataIn[0];
      2'd1: oDataOut = iDataIn[1];
      2'd2: oDataOut = iDataIn[2];
      2'd3: oDataOut = iDataIn[3];
      default: oDataOut = 1'b0;
    endcase
  end

endmodule

`timescale 1ns / 1ps

module decoder_3to8 (
  input  wire [2:0] iAddr,
  input  wire       iEnable,
  output reg  [7:0] oDecOut
);

  always @(*) begin
    oDecOut = 8'b0000_0000;
    if (iEnable) begin
      oDecOut = 8'b0000_0001 << iAddr;
    end
  end

endmodule

`timescale 1ns / 1ps

module compare_4bit (
  input  wire [3:0] iA,
  input  wire [3:0] iB,
  output wire       oGt,
  output wire       oEq,
  output wire       oLt
);

  assign oGt = (iA > iB);
  assign oEq = (iA == iB);
  assign oLt = (iA < iB);

endmodule

`timescale 1ns / 1ps

module full_adder (
  input  wire iA,
  input  wire iB,
  input  wire iCin,
  output wire oSum,
  output wire oCout
);

  assign oSum  = iA ^ iB ^ iCin;
  assign oCout = (iA & iB) | (iA & iCin) | (iB & iCin);

endmodule
module rca_4bit (
  input  wire [3:0] iA,
  input  wire [3:0] iB,
  input  wire       iCin,
  output wire [3:0] oSum,
  output wire       oCout
);

  wire [2:0] wCarry;

  full_adder u_fa0 (.iA(iA[0]), .iB(iB[0]), .iCin(iCin),      .oSum(oSum[0]), .oCout(wCarry[0]));
  full_adder u_fa1 (.iA(iA[1]), .iB(iB[1]), .iCin(wCarry[0]), .oSum(oSum[1]), .oCout(wCarry[1]));
  full_adder u_fa2 (.iA(iA[2]), .iB(iB[2]), .iCin(wCarry[1]), .oSum(oSum[2]), .oCout(wCarry[2]));
  full_adder u_fa3 (.iA(iA[3]), .iB(iB[3]), .iCin(wCarry[2]), .oSum(oSum[3]), .oCout(oCout));

endmodule

