`timescale 1ns / 1ps

module sync_2ff (
  input  wire iClkDst,
  input  wire iRst,
  input  wire iSigIn,
  output wire oSigOut
);

  reg rSync0;
  reg rSync1;

  always @(posedge iClkDst) begin
    if (iRst) begin
      rSync0 <= 1'b0;
      rSync1 <= 1'b0;
    end
    else begin
      rSync0 <= iSigIn;
      rSync1 <= rSync0;
    end
  end

  assign oSigOut = rSync1;

endmodule

`timescale 1ns / 1ps

module sync_edge_detect (
  input  wire iClkDst,
  input  wire iRst,
  input  wire iSigIn,
  output wire oPulseOut
);

  reg rSync0;
  reg rSync1;
  reg rSync1Dly;

  always @(posedge iClkDst) begin
    if (iRst) begin
      rSync0   <= 1'b0;
      rSync1   <= 1'b0;
      rSync1Dly <= 1'b0;
    end
    else begin
      rSync0   <= iSigIn;
      rSync1   <= rSync0;
      rSync1Dly <= rSync1;
    end
  end

  assign oPulseOut = rSync1 & ~rSync1Dly;

endmodule

`timescale 1ns / 1ps

module async_fifo #(
  parameter DATA_WIDTH = 8,
  parameter ADDR_WIDTH = 4
) (
  input  wire                  iClkW,
  input  wire                  iRstW,
  input  wire                  iWrEn,
  input  wire [DATA_WIDTH-1:0] iWrData,
  input  wire                  iClkR,
  input  wire                  iRstR,
  input  wire                  iRdEn,
  output reg  [DATA_WIDTH-1:0] oRdData,
  output wire                  oFull,
  output wire                  oEmpty
);

  localparam DEPTH = (1 << ADDR_WIDTH);
  localparam PTR_WIDTH = ADDR_WIDTH + 1;

  reg [DATA_WIDTH-1:0] rMem [0:DEPTH-1];

  reg [PTR_WIDTH-1:0] rWrBin;
  reg [PTR_WIDTH-1:0] rWrGray;
  reg [PTR_WIDTH-1:0] rRdBin;
  reg [PTR_WIDTH-1:0] rRdGray;

  reg [PTR_WIDTH-1:0] rRdGrayW0;
  reg [PTR_WIDTH-1:0] rRdGrayW1;
  reg [PTR_WIDTH-1:0] rWrGrayR0;
  reg [PTR_WIDTH-1:0] rWrGrayR1;

  wire wWrFire = iWrEn & ~oFull;
  wire wRdFire = iRdEn & ~oEmpty;

  wire [PTR_WIDTH-1:0] wWrBinNext  = rWrBin + {{(PTR_WIDTH-1){1'b0}}, wWrFire};
  wire [PTR_WIDTH-1:0] wRdBinNext  = rRdBin + {{(PTR_WIDTH-1){1'b0}}, wRdFire};
  wire [PTR_WIDTH-1:0] wWrGrayNext = (wWrBinNext >> 1) ^ wWrBinNext;
  wire [PTR_WIDTH-1:0] wRdGrayNext = (wRdBinNext >> 1) ^ wRdBinNext;

  assign oFull = (wWrGrayNext == {~rRdGrayW1[PTR_WIDTH-1:PTR_WIDTH-2],
                                  rRdGrayW1[PTR_WIDTH-3:0]});
  assign oEmpty = (wRdGrayNext == rWrGrayR1);

  always @(posedge iClkW or posedge iRstW) begin
    if (iRstW) begin
      rWrBin  <= {PTR_WIDTH{1'b0}};
      rWrGray <= {PTR_WIDTH{1'b0}};
    end
    else begin
      if (wWrFire) begin
        rMem[rWrBin[ADDR_WIDTH-1:0]] <= iWrData;
      end
      rWrBin  <= wWrBinNext;
      rWrGray <= wWrGrayNext;
    end
  end

  always @(posedge iClkR or posedge iRstR) begin
    if (iRstR) begin
      rRdBin  <= {PTR_WIDTH{1'b0}};
      rRdGray <= {PTR_WIDTH{1'b0}};
      oRdData <= {DATA_WIDTH{1'b0}};
    end
    else begin
      if (wRdFire) begin
        oRdData <= rMem[rRdBin[ADDR_WIDTH-1:0]];
      end
      rRdBin  <= wRdBinNext;
      rRdGray <= wRdGrayNext;
    end
  end

  always @(posedge iClkW or posedge iRstW) begin
    if (iRstW) begin
      rRdGrayW0 <= {PTR_WIDTH{1'b0}};
      rRdGrayW1 <= {PTR_WIDTH{1'b0}};
    end
    else begin
      rRdGrayW0 <= rRdGray;
      rRdGrayW1 <= rRdGrayW0;
    end
  end

  always @(posedge iClkR or posedge iRstR) begin
    if (iRstR) begin
      rWrGrayR0 <= {PTR_WIDTH{1'b0}};
      rWrGrayR1 <= {PTR_WIDTH{1'b0}};
    end
    else begin
      rWrGrayR0 <= rWrGray;
      rWrGrayR1 <= rWrGrayR0;
    end
  end

endmodule

`timescale 1ns / 1ps

module fsm_moore_3state (
  input  wire       iClk,
  input  wire       iRst,
  input  wire       iStart,
  input  wire       iDoneIn,
  output wire [1:0] oState,
  output reg        oBusy,
  output reg        oComplete
);

  localparam IDLE  = 2'd0;
  localparam READY = 2'd1;
  localparam DONE  = 2'd2;

  reg [1:0] rCurState;

  assign oState = rCurState;

  always @(posedge iClk) begin
    if (iRst) begin
      rCurState <= IDLE;
      oBusy     <= 1'b0;
      oComplete <= 1'b0;
    end
    else begin
      case (rCurState)
        IDLE: begin
          oBusy     <= 1'b0;
          oComplete <= 1'b0;
          if (iStart) begin
            rCurState <= READY;
          end
        end
        READY: begin
          oBusy     <= 1'b1;
          oComplete <= 1'b0;
          if (iDoneIn) begin
            rCurState <= DONE;
          end
        end
        DONE: begin
          oBusy     <= 1'b0;
          oComplete <= 1'b1;
          rCurState <= IDLE;
        end
        default: begin
          rCurState <= IDLE;
          oBusy     <= 1'b0;
          oComplete <= 1'b0;
        end
      endcase
    end
  end

endmodule

`timescale 1ns / 1ps

module fsm_moore_3state_3p (
  input  wire       iClk,
  input  wire       iRst,
  input  wire       iStart,
  input  wire       iDoneIn,
  output wire [1:0] oState,
  output reg        oBusy,
  output reg        oComplete
);

  localparam IDLE  = 2'd0;
  localparam READY = 2'd1;
  localparam DONE  = 2'd2;

  reg [1:0] rCurState;
  reg [1:0] rNxtState;

  assign oState = rCurState;

  always @(posedge iClk or posedge iRst) begin
    if (iRst) begin
      rCurState <= IDLE;
    end
    else begin
      rCurState <= rNxtState;
    end
  end

  always @(*) begin
    rNxtState = rCurState;
    case (rCurState)
      IDLE: begin
        if (iStart) begin
          rNxtState = READY;
        end
      end
      READY: begin
        if (iDoneIn) begin
          rNxtState = DONE;
        end
      end
      DONE: begin
        rNxtState = IDLE;
      end
      default: begin
        rNxtState = IDLE;
      end
    endcase
  end

  always @(*) begin
    oBusy     = 1'b0;
    oComplete = 1'b0;
    case (rCurState)
      READY: begin
        oBusy = 1'b1;
      end
      DONE: begin
        oComplete = 1'b1;
      end
      default: begin
        oBusy     = 1'b0;
        oComplete = 1'b0;
      end
    endcase
  end

endmodule
